mapper.select:
SELECT COUNT(*)
  FROM course
 WHERE course_id = #{courseId}

SELECT sr.sale_num , c.creator_id , cr.creator_nm , sr.course_id , c.course_title , sr.student_id , sr.amount , sr.sale_status , sr.occurred_at FROM sale_record sr INNER JOIN course c ON sr.course_id = c.course_id INNER JOIN creator cr ON c.creator_id = cr.creator_id WHERE 1=1
AND c.creator_id = #{creatorId}
AND sr.occurred_at >= #{fromDate}
AND sr.occurred_at < #{toDate}
ORDER BY sr.occurred_at DESC, sr.sale_serl_num DESC
